<span class="line"><span style="color:#F4F5EC">        cout </span><span style="color:#B8EF58;font-weight:bold">&#x3C;&#x3C;</span><span style="color:#F4F5EC"> endl</span><span style="color:#BAC1AD">;</span></span>
