<span class="line"><span style="color:#B8EF58;font-weight:bold">    for</span><span style="color:#BAC1AD">(</span><span style="color:#B8EF58;font-weight:bold">int</span><span style="color:#F4F5EC"> i</span><span style="color:#B8EF58;font-weight:bold">=</span><span style="color:#F0BF6A">0</span><span style="color:#BAC1AD">;</span><span style="color:#F4F5EC">i</span><span style="color:#B8EF58;font-weight:bold">&#x3C;</span><span style="color:#F4F5EC">r</span><span style="color:#B8EF58;font-weight:bold">-</span><span style="color:#F4F5EC">l</span><span style="color:#B8EF58;font-weight:bold">+</span><span style="color:#F0BF6A">1</span><span style="color:#BAC1AD">;</span><span style="color:#F4F5EC">i</span><span style="color:#B8EF58;font-weight:bold">++</span><span style="color:#BAC1AD">)</span></span>
