<span class="line"><span style="color:#B8EF58;font-weight:bold">        for</span><span style="color:#BAC1AD"> (</span><span style="color:#B8EF58;font-weight:bold">int</span><span style="color:#F4F5EC"> j </span><span style="color:#B8EF58;font-weight:bold">=</span><span style="color:#F0BF6A"> 0</span><span style="color:#BAC1AD">;</span><span style="color:#F4F5EC"> j </span><span style="color:#B8EF58;font-weight:bold">&#x3C;</span><span style="color:#F4F5EC"> n</span><span style="color:#BAC1AD">;</span><span style="color:#F4F5EC"> j</span><span style="color:#B8EF58;font-weight:bold">++</span><span style="color:#BAC1AD">)</span></span>
