<span class="line"><span style="color:#F4F5EC">    printf</span><span style="color:#BAC1AD">(</span><span style="color:#D3E69A">"第一个匹配的子串位置是[%d,%d]</span><span style="color:#F0BF6A">\\n</span><span style="color:#D3E69A">"</span><span style="color:#BAC1AD">,</span><span style="color:#F4F5EC">i</span><span style="color:#B8EF58;font-weight:bold">-</span><span style="color:#F4F5EC">m</span><span style="color:#BAC1AD">,</span><span style="color:#F4F5EC">i</span><span style="color:#B8EF58;font-weight:bold">-</span><span style="color:#F0BF6A">1</span><span style="color:#BAC1AD">);</span><span style="color:#9AA28D;font-style:italic"> // 输出所在区间</span></span>
